package main

import (
	"fmt"
	"net/http"
	"io/ioutil"
)

func handleRequest(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		fmt.Fprintf(w, "Error reading request body: %v", err)
		return
	}

	// Close the request body to free up resources
	defer r.Body.Close()

	// Print the content of the request body
	fmt.Fprintf(w, "Request Content: %s", body)
}

func main() {
	http.HandleFunc("/", handleRequest)
	http.ListenAndServe(":8080", nil)
}
```

This program sets up a simple HTTP server that listens on port 8080. When a request is made to the root URL (`/`), it reads the request body and prints its content to the response. Make sure to handle the request body carefully and close it to avoid resource leaks.

